FUNCTION_BLOCK AGVControlSystem
VAR_INPUT
    MaterialRequest : INT;
END_VAR
VAR_OUTPUT
    AGV1_Ready : BOOL := TRUE;
    AGV2_Ready : BOOL := TRUE;
    AGV3_Ready : BOOL := TRUE;
END_VAR
VAR
    MaterialQueue : ARRAY[1..10] OF INT;
    AGVPosition : ARRAY[1..3] OF INT;
    QueueHead : INT := 1;
    QueueTail : INT := 1;
    QueueCount : INT := 0;
    i : INT;
    j : INT;
    TaskAssigned : BOOL;
    CurrentTask : INT;
    AGVIndex : INT;
    IsReady : BOOL;
    IsBusy : BOOL;
    ValidRequest : BOOL;
    MinPos : INT;
END_VAR


    ValidRequest := TRUE;
    If MaterialRequest < 0 Then
        ValidRequest := FALSE;
    End_IF;

    If ValidRequest = TRUE Then
        If QueueCount < 10 Then
            MaterialQueue[QueueTail] := MaterialRequest;
            QueueTail := QueueTail + 1;
            If QueueTail > 10 Then
                QueueTail := 1;
            End_IF;
            QueueCount := QueueCount + 1;
        End_IF;
    End_IF;

    TaskAssigned := FALSE;
    CurrentTask := 0;

    For i := 1 To QueueCount Do
        CurrentTask := MaterialQueue[i];
        IsBusy := FALSE;
        For j := 1 To 3 Do
            If AGVPosition[j] = CurrentTask Then
                IsBusy := TRUE;
                Break;
            End_IF;
        End_For;
        If IsBusy = FALSE Then
            Break;
        End_IF;
    End_For;

    If TaskAssigned = FALSE Then
        For i := 1 To 3 Do
            AGVIndex := i;
            IsReady := TRUE;
            If AGVPosition[AGVIndex] <> 0 Then
                IsReady := FALSE;
            End_IF;
            If IsReady = TRUE Then
                If QueueCount > 0 Then
                    For j := 1 To QueueCount Do
                        CurrentTask := MaterialQueue[j];
                        IsBusy := FALSE;
                        For k := 1 To 3 Do
                            If AGVPosition[k] = CurrentTask Then
                                IsBusy := TRUE;
                                Break;
                            End_IF;
                        End_For;
                        If IsBusy = FALSE Then
                            AGVPosition[AGVIndex] := CurrentTask;
                            If AGVIndex = 1 Then
                                AGV1_Ready := FALSE;
                            Else If AGVIndex = 2 Then
                                AGV2_Ready := FALSE;
                            Else
                                AGV3_Ready := FALSE;
                            End_IF;
                            TaskAssigned := TRUE;
                            Break;
                        End_IF;
                    End_For;
                End_IF;
            End_IF;
            If TaskAssigned = TRUE Then
                Break;
            End_IF;
        End_For;
    End_IF;

    For i := 1 To 3 Do
        MinPos := 0;
        If AGVPosition[i] < MinPos Then
            MinPos := AGVPosition[i];
        End_IF;
        If MinPos < 0 Then
            AGVPosition[i] := 0;
        End_IF;
    End_For;

    For i := 1 To 3 Do
        If AGVPosition[i] = 0 Then
            If i = 1 Then
                AGV1_Ready := TRUE;
            Else If i = 2 Then
                AGV2_Ready := TRUE;
            Else
                AGV3_Ready := TRUE;
            End_IF;
        End_IF;
    End_For;

END_FUNCTION_BLOCK

